import csv

with open('data.csv', mode='r') as file:
    csv_reader = csv.DictReader(file)
    filtered_data = []
    for row in csv_reader:
        try:
            if int(row['age']) > 30:
                filtered_data.append(row)
        except ValueError:
            pass

print(filtered_data)
